INSERT INTO `loci` VALUES (1,10,27,'R13','2013-05-29 00:00:00','2013-05-29 00:00:00','13.35','12.73',NULL,'13/S/29',NULL,'Surface cleaning, lots of medium sized stones.',NULL,NULL,'?'),(2,10,29,'R13','2013-05-29 00:00:00','2013-06-04 00:00:00','12.73','12.54','13/S/27','13/S/45',NULL,'North side of square. Medium dark soil with medium sized stones, some mudbrick chunks. Locus changed to 13/S/45 because of depth and soil change.',NULL,NULL,'?'),(3,10,45,'R13','2013-06-04 00:00:00','2013-06-05 00:00:00','12.54','12.31','13/S/29','13/S/48',NULL,'East side of square; brownish orange soil mixed with fired mudbricks; disturbed by pit 13/S/79.',NULL,NULL,'?'),(4,10,48,'R13','2013-06-05 00:00:00','2013-06-10 00:00:00','12.31','12.15','13/S/45','13/S/56',NULL,'Gravely, hard packed soil.',NULL,NULL,'?'),(5,10,56,'R13','2013-06-07 00:00:00','2013-06-11 00:00:00','12.33','11.98','13/S/48',NULL,NULL,'Hard packed soil, gravely, with mudbrick and mudbrick chunks.',NULL,NULL,'?'),(6,10,79,'R13','2013-06-13 00:00:00','2013-06-13 00:00:00',NULL,NULL,NULL,NULL,NULL,'Locus only opened to describe pit visible in W section of square.',NULL,NULL,'?'),(7,10,82,'R13','2013-06-13 00:00:00','2013-06-13 00:00:00',NULL,NULL,NULL,NULL,NULL,'Locus only opened to describe pit visible in S section of square.',NULL,NULL,'?'),(8,10,38,'S12','2013-06-03 00:00:00','2013-06-03 00:00:00','12.80','12.83',NULL,'13/S/40',NULL,'Surface cleaning; lots of stones, pottery, flint, and bones.',NULL,NULL,'?'),(9,10,40,'S12','2013-06-03 00:00:00','2013-06-06 00:00:00','12.83','12.37','13/S/38','13/S/53',NULL,'Topsoil; mixed pottery.',NULL,NULL,'?'),(10,10,53,'S12','2013-06-06 00:00:00','2013-06-10 00:00:00','12.37','12.01','13/S/40','13/S/60',NULL,'Possibly the continuation of pit 13/S/70 from S13; pottery mixed.',NULL,NULL,'?'),(11,10,60,'S12','2013-06-10 00:00:00','2013-06-11 00:00:00','12.09','12.01','13/S/53','13/S/68, 13/S/69',NULL,'Same as 13/S/53; locus probably cut by pit (13/S/70) on north side.',NULL,NULL,'?'),(12,10,68,'S12','2013-06-11 00:00:00','2013-06-12 00:00:00','11.99','11.78','13/S/60',NULL,'13/S/69','Locus cut by pit? Locus was changed to 13/S/68 when 13/WL005 was encountered. Same material as 13/S/60.',NULL,NULL,'?'),(13,10,69,'S12','2013-06-12 00:00:00','2013-06-12 00:00:00','11.95','11.95','13/S/60',NULL,'13/S/68','Cleaning top of 13/WL005.',NULL,NULL,'?'),(14,10,3,'S13','2013-05-20 00:00:00','2013-05-21 00:00:00','12.79','12.28',NULL,'13/S/7',NULL,'Surface cleaning; lots of stones, pottery, flint, and bones. Components differed than the rest of the square with soil consistency and lesser amount of stones.',NULL,NULL,'?'),(15,10,7,'S13','2013-05-22 00:00:00','2013-05-27 00:00:00','12.66','12.19','13/S/3','13/S/21, 13/S/22, 13/S/32',NULL,'Subsoil in entire square; medium sized stones with mudbrick material coming up in the SW corner.',NULL,NULL,'?'),(16,10,21,'S13','2013-05-27 00:00:00','2013-05-30 00:00:00','12.4','11.93','13/S/7','13/S/34',NULL,'North of 13/WL001 outside building. Lots of stones with a small amount of mudbrick chunks.',NULL,NULL,'?'),(17,10,22,'S13','2013-05-27 00:00:00','2013-05-31 00:00:00','12.38','11.97','13/S/7','13/S/59','13/S/32','South of 13/WL001. Darker soil with mudbrick chunks possibly excavated below living surface 13/S/32.',NULL,'Pottery EB with one Chalcolithic and one MB.','?'),(18,10,32,'S13','2013-05-30 00:00:00','2013-05-31 00:00:00','12.33','12.00','13/S/7','13/S/59','13/S/22','Living surface in SW corner of square, abuts bottom of 13/WL001. Packed grayish earth, gravel. EB pottery.',NULL,NULL,'?'),(19,10,34,'S13','2013-05-30 00:00:00','2013-05-31 00:00:00','11.95','11.81','13/S/21',NULL,NULL,'See description on 13/S/21; locus changed because we were below 13/WL001.',NULL,NULL,'?'),(20,10,36,'S13','2013-05-31 00:00:00','2013-05-31 00:00:00','12.08','12.01','13/S/21, 13/WL001',NULL,NULL,'Combine with 13/S/34. Locus opened because of missing stone in 13/WL001.',NULL,NULL,'?'),(21,10,59,'S13','2013-06-10 00:00:00','2013-06-12 00:00:00','12.03','11.72','13/S/22, 13/S/32','13/S/64, 13/S/65, 13/S/66, 13/S/67',NULL,'South of 13/WL001, west of 13/WL004. Inside the building. Locus was probably cut by pit (13/S/70) from a later period. Softer soil mixed with mudbrick material.',NULL,NULL,'?'),(22,10,64,'S13','2013-06-11 00:00:00','2013-06-12 00:00:00','11.88','11.71','13/S/59','13/S/71',NULL,'East of 13/WL004.',NULL,NULL,'?'),(23,10,65,'S13','2013-06-11 00:00:00','2013-06-12 00:00:00','11.92','11.68','13/S/59',NULL,NULL,'West of 13/WL004. Locus cut by pit (13/S/70) and extends beneath 13/WL004. At the bottom of this locus we encountered 13/WL006. Locus should be combined with 13/S/66.',NULL,NULL,'?'),(24,10,66,'S13','2013-06-11 00:00:00','2013-06-12 00:00:00','11.92','11.69','13/S/59',NULL,NULL,'S of 13/WL001, small corner in NW. Should be combined with 13/S/65.',NULL,NULL,'?'),(25,10,70,'S13','2013-06-12 00:00:00','2013-06-13 00:00:00','11.87','11.70','13/S/59',NULL,NULL,'Pit visible in southern section. Excavated as a pit only in the southern missing part of 13/WL004.',NULL,NULL,'?'),(26,10,71,'S13','2013-06-12 00:00:00','2013-06-13 00:00:00','11.73','11.64','13/S/64',NULL,NULL,'Corner between 13/WL002 and 13/WL004 in south. Probably cut by pit 13/S/70.',NULL,NULL,'?'),(27,10,74,'S13','2013-06-13 00:00:00','2013-06-13 00:00:00','12.03','11.8',NULL,NULL,NULL,'Removal of 13/WL004.',NULL,NULL,'?'),(28,10,81,'S13','2013-06-13 00:00:00','2013-06-13 00:00:00',NULL,NULL,NULL,NULL,NULL,'Locus only opened to describe pit visible in N section of square.',NULL,NULL,'?'),(29,10,2,'T14','2013-05-20 00:00:00','2013-05-21 00:00:00','12.28','12.05',NULL,'13/S/8',NULL,'Surface cleaning; lots of stones, pottery, flint, and bones',NULL,NULL,'?'),(30,10,8,'T14','2013-05-22 00:00:00','2013-05-23 00:00:00','12.08','11.95','13/S/2','13/S/13',NULL,'Continued cleaning in entire square; medium sized stones.',NULL,NULL,'?'),(31,10,13,'T14','2013-05-23 00:00:00','2013-05-29 00:00:00','12.03','11.75','13/S/8','13/S/15,  13/S/16, 13/S/37',NULL,'Subsoil in entire square; medium sized stones and brick material in SW corner and in the center','Subsoil.',NULL,'?'),(32,10,15,'T14','2013-05-24 00:00:00','2013-06-03 00:00:00','11.84','11.60','13/S/13','13/S/28, 13/S/39','13/S/16','Lots of stones, bigger stones in the center, cleaning in the center.',NULL,NULL,'?'),(33,10,16,'T14','2013-05-24 00:00:00','2013-05-27 00:00:00','11.82','11.67','13/S/13','13/S/20','13/S/15','Locus 13/S/15 changed in NW corner due to fewer frequency of stones and lighter color earth.',NULL,'Larger stones later removed but entire locus should be combined with 13/S/15.','?'),(34,10,20,'T14','2013-05-27 00:00:00','2013-06-05 00:00:00','11.75',NULL,'13/S/16','13/S/47',NULL,'NE corner soil loose with chalky mudbrick chunks.',NULL,NULL,'?'),(35,10,28,'T14','2013-05-29 00:00:00','2013-06-05 00:00:00','11.84','11.62','13/S/15','13/S/46',NULL,'SW corner of square, soft grey material with lots of pottery (3 full buckets in one day). Originally thought it was a pit but we could not discern boundary lines. Possibly pottery dump; pottery contained no diagnostics.',NULL,NULL,'?'),(36,10,37,'T14','2013-05-31 00:00:00','2013-06-13 00:00:00','12.11','11.52','13/S/15',NULL,NULL,'Large stones in center of square, possibly collapse from wall?',NULL,NULL,'?'),(37,10,39,'T14','2013-06-03 00:00:00','2013-06-05 00:00:00','11.60','11.49','13/S/15','13/S/49','13/S/28','South side of square, collapsed mudbricks. Mudbricks contained small amounts of  pottery (PT3).',NULL,NULL,'?'),(38,10,46,'T14','2013-06-05 00:00:00','2013-06-05 00:00:00','11.55','11.51','13/S/28','13/S/49',NULL,'Should be combined with 13/S/39. Locus opened because it was under suspected pit (13/S/28).',NULL,NULL,'?'),(39,10,47,'T14','2013-06-05 00:00:00','2013-06-13 00:00:00','11.49','11.34','13/S/20',NULL,NULL,'NE corner of square; very loose orangey brown soil with few stones.',NULL,NULL,'?'),(40,10,49,'T14','2013-06-05 00:00:00','2013-06-10 00:00:00','11.56','11.44','13/S/39, 13/S/46','13/S/61, 13/S/62',NULL,'Mudbricks and mudbrick material; possibly from collapse of 13/WL003.',NULL,NULL,'?'),(41,10,52,'T14','2013-06-06 00:00:00','2013-06-07 00:00:00','11.65','11.52','13/S/15','13/S/58',NULL,'Cleaning between stones in NW corner; darker soil. Locus was changed to 13/S/58 when soil became lighter.',NULL,NULL,'?'),(42,10,58,'T14','2013-06-07 00:00:00','2013-06-11 00:00:00','11.52','11.32','13/S/52','13/S/63',NULL,'Lighter soil above the floor (13/S/63); locus similar to 13/S/52 changed to 13/S/58 due to lighter soil.',NULL,NULL,'?'),(43,10,61,'T14','2013-06-10 00:00:00','2013-06-12 00:00:00','11.46','11.13','13/S/49',NULL,NULL,'East of 13/WL003. Very hard packed soil with mudbrick and mudbrick chunks.',NULL,NULL,'?'),(44,10,62,'T14','2013-06-10 00:00:00','2013-06-12 00:00:00','11.49','11.23','13/S/49','13/S/72',NULL,'West of 13/WL003. Very hard packed soil with mudbrick and mudbrick chunks. Contained one complete fallen mudbrick (33 x 34 x14 cm).',NULL,NULL,'?'),(45,10,63,'T14','2013-06-11 00:00:00','2013-06-13 00:00:00','11.49','11.23','13/S/58',NULL,NULL,'Floor in NW corner; greyish packed beaten earth floor, approximately 5 cm thick. Softer material below. All pottery EB.',NULL,NULL,'?'),(46,10,72,'T14','2013-06-12 00:00:00','2013-06-13 00:00:00','11.23','11.13','13/S/62',NULL,NULL,'Combine with 13/S/62.',NULL,NULL,'?'),(47,10,80,'T14','2013-06-13 00:00:00','2013-06-13 00:00:00',NULL,NULL,NULL,NULL,NULL,'Locus only opened to describe pit visible in W section of square.',NULL,NULL,'?'),(48,10,1,'U14','2013-05-20 00:00:00','2013-05-22 00:00:00','12.01','11.59',NULL,'13/S/9',NULL,'Surface cleaning; lots of stones, pottery, flint, and bones.',NULL,NULL,'?'),(49,10,9,'U14','2013-05-22 00:00:00','2013-05-27 00:00:00','11.87','11.29','13/S/1','13/S/23',NULL,'Hard dark soil with many medium stones.',NULL,NULL,'?'),(50,10,23,'U14','2013-05-28 00:00:00','2013-05-28 00:00:00','11.38','11.20','13/S/9',NULL,NULL,'Hard dark soil with many medium stones; locus closed when square was closed.',NULL,NULL,'?'),(51,10,4,'R9','2013-05-20 00:00:00','2013-05-22 00:00:00','14.11','13.77','surface','13/S/10',NULL,'Surface cleaning. Grey friable topsoil with frequent inclusions of small and medium limestone rocks, frequent pottery, flint and occasional fragments of basalt, some of which are worked.','Topsoil/alluvial buildup.',NULL,'?'),(52,10,5,'S9','2013-05-20 00:00:00','2013-05-22 00:00:00','13.88','13.61','surface','13/S/11',NULL,'Surface cleaning. Greyish brown friable topsoil with frequent inclusions of small and medium limestone rocks, frequent pottery and flint, and occasional fragments of basalt, some of which are worked.','Topsoil/alluvial buildup.',NULL,'?'),(53,10,6,'T8','2013-05-20 00:00:00','2013-05-22 00:00:00','13.67','13.36','surface','13/S/12',NULL,'Surface cleaning. Greyish brown topsoil with frequent inclusions of small and medium limestone, frequent pottery and flint, and occasional fragments of basalt, some of which is worked.','Topsoil/alluvial buildup.',NULL,'?'),(54,10,10,'R9','2013-05-22 00:00:00','2013-05-24 00:00:00','13.90','13.60','13/S/4','13/S/19',NULL,'A layer spreading across whole square of mid greyish brown sandy clayey soil with frequent inclusions of small limestone fieldstones. Loose and friable soil.','Subsoil below topsoil.',NULL,'?'),(55,10,11,'S9','2013-05-22 00:00:00','2013-05-24 00:00:00','13.75','13.54','13/S/005','13/S/014',NULL,'Mid brown sandy clay - friable with occasional-moderate inclusions of small and medium fieldstones.','Subsoil.',NULL,'?'),(56,10,12,'T8','2013-05-22 00:00:00','2013-06-06 00:00:00','13.54','13.15','13/S/6','13/S/17, 13/S/18, 13/S/33',NULL,'Mid brown sandy clay friable with moderate inclusions of small and medium sized fieldstones.',NULL,NULL,'?'),(57,10,14,'S9','2013-05-24 00:00:00','2013-05-06 00:00:00','13.62',NULL,'13/S/11','13/S/30, 13/S/31, 13/S/35',NULL,'A layer of mid brown loose soil densely packed with very frequent small and medium fieldstones. Possible later intrusion (robber cut or pitting) in SW corner.',NULL,NULL,'?'),(58,10,17,'T8','2013-05-24 00:00:00','2013-05-28 00:00:00','13.50','13.15','13/S/12','13/S/26',NULL,'After removal of subsoil there was a scatter of fieldstones in NW corner. Locus change in case was wall. In fact was dump with medium and large fieldstones.',NULL,NULL,'?'),(59,10,18,'T8','2013-05-24 00:00:00','2013-05-28 00:00:00','13.35','13.12','13/S/18','13/S/24',NULL,'NE corner had more soil and less stones than NW corner so has been treated as separate locus. Probably the same as 13/S/17 but with less stones.',NULL,NULL,'?'),(60,10,19,'R9','2013-05-24 00:00:00','2013-06-03 00:00:00','13.79','13.49','13/S/10','13/S/25',NULL,'Light brown friable sandy clay with moderate inclusions of small and medium limestone fieldstones. More stony than 13/S/10. Layer spreads across whole square.',NULL,NULL,'?'),(61,10,24,'T8','2013-05-28 00:00:00','2013-06-10 00:00:00','13.23','12.91','13/S/18','None',NULL,'Changed locus in NE corner as soil became slightly lighter but still had very frequent fieldstones.',NULL,NULL,'?'),(62,10,25,'R9','2013-05-28 00:00:00','2013-06-05 00:00:00','13.69','13.31','13/S/19','None',NULL,'Light brown sandy clay - soft rather than friable. Occasional inclusions of small and medium fieldstones. Very frequent pottery. Comes down onto surface on eastern side - layer of frequent stones on west side and possible robber trench or pitting at south.',NULL,NULL,'?'),(63,10,26,'T8','2013-05-29 00:00:00',NULL,'13.32','13.04','13/S/17','None',NULL,'Soil slightly lighter in colour. Stones now appear to be tumble and are all loose and floating. Locus represents removal of stones.',NULL,NULL,'?'),(64,10,30,'S9','2013-05-29 00:00:00','2013-06-05 00:00:00','13.26','13.17','13/S/14','None',NULL,'An area of much darker sandy clayey soil. Originally thought may have been a pit but after removal of western half of square seems to carry on. May reflect either a robber trench or large pit. End level = -- not excavated to depth.',NULL,NULL,'?'),(65,10,31,'S9','2013-05-30 00:00:00','2013-06-05 00:00:00','13.58','13.05','13/S/14','None',NULL,'The removal of a cluster of small fieldstones packed into a mid brown sandy clay. Seemed to be circular and considered a possible pit. Half sectioned vertically SE-NW. Unlikely to represent a pit as pot no different to surrounds. Removed completely.',NULL,NULL,'?'),(66,10,33,'T8','2013-05-30 00:00:00','2013-06-03 00:00:00','13.55','13.10','13/S/12','13/S/43, 13/S/44',NULL,'Removal of SW part of square. Mid brown loose/soft sandy clay with moderate-frequent inclusions of fieldstones. Pot includes MB sherds in its SE part - possible pit intrusion. Also soil feels different in texture and matrix and given different locus (13/S/41).',NULL,NULL,'?'),(67,10,35,'S9','2013-05-31 00:00:00','2013-06-05 00:00:00','13.30','13.01','13/S/14','None',NULL,'Removal of stones and soil in NE part of square yielding mostly EB pottery. Similar to 13/S/14 but less and stones and more soil. Still frequent inclusions of fieldstones.',NULL,NULL,'?'),(68,10,41,'T8','2013-06-03 00:00:00','2013-06-03 00:00:00','13.18','12.95','13/S/33','None',NULL,'Removal of darker, looser soil of 13/WL007. Represents either robbing out of wall or a pit cut into southern part of square.',NULL,NULL,'?'),(69,10,42,'S9','2013-06-03 00:00:00','2013-06-05 00:00:00','13.48','13.40','13/S/14','None',NULL,'Removal of looser, darker soil in southern part of square. Distinctly darker than rest of square with later pottery. Also trucates probable wall. Likely to be a pit that could extend into R9.',NULL,NULL,'?'),(70,10,43,'T8','2013-06-03 00:00:00',NULL,'13.15','13.04','13/S/33','13/S/57',NULL,'Cleaning up of loose stones and soil which lies over and around 13/WL007.',NULL,NULL,'?'),(71,10,44,'T8','2013-06-03 00:00:00',NULL,'13.19','13.09','13/S/33','None',NULL,'Reduction of ground in SW corner of square. Frequent inclusions of fieldstones. No obvious features.',NULL,NULL,'?'),(72,10,50,'R17','2013-06-05 00:00:00','2013-06-07 00:00:00','12.08','11.51','Surface','13/S/55',NULL,'Surface cleaning and removal of topsoil.',NULL,NULL,'?'),(73,10,51,'Q17','2013-06-05 00:00:00','2013-06-06 00:00:00','12.35','11.82','Surface','13/S/54',NULL,'Surface cleaning and removal of topsoil.',NULL,NULL,'?'),(74,10,54,'Q17','2013-06-06 00:00:00','2013-06-11 00:00:00','12.21','11.45','13/S/51','13/S/67, 13/S/73',NULL,'Removal of subsoil. Reddish brown silty clayey soil - moderately firm. Very few fieldstones for first locus then start to come down on them.',NULL,NULL,'?'),(75,10,55,'R17','2013-06-07 00:00:00','2013-06-13 00:00:00','11.51','11.31','13/S/50','13/S/75',NULL,'Removal of subsoil in N and SE parts of square. Moderately compact, reddish brown in colour. Not many rocks and very mixed pottery. Possibly represents some dumping/leveling layer.',NULL,NULL,'?'),(76,10,57,'T8','2013-06-07 00:00:00','2013-06-07 00:00:00','11.90','11.49','13/S/43',NULL,NULL,'Removal of cluster of small stones. Proved to be dumped or fallen (next to 13/WL007).',NULL,NULL,'?'),(77,10,67,'Q17','2013-06-11 00:00:00','2013-06-13 00:00:00','12.02','11.64','13/S/54','13/S/73',NULL,'Similar to 13/S/54 but with a decreased frequency of medium fieldstones. Pottery has early material but still mixed. May overlay stones of 13/S/54.',NULL,NULL,'?'),(78,10,73,'R17','2013-06-12 00:00:00','2013-06-13 00:00:00','12.03','11.59','13/S/54, 13/S/57',NULL,NULL,'Closing/cleaning locus for square.',NULL,NULL,'?'),(79,10,75,'R17','2013-06-13 00:00:00','2013-06-13 00:00:00','11.55','11.33','13/S/55',NULL,NULL,'Represents the removal of a cluster of small stones along the alignment of bigger ones to establish presence or absence of wall. Pottery is mixed and stone removal proved inconclusive. If is blocking is much later.',NULL,NULL,'?'),(80,10,76,'R9','2013-06-13 00:00:00','2013-06-13 00:00:00','11.54','11.54','13/S/25',NULL,NULL,'Final clean/closing locus of square revealing dense spread of small fieldstones mixed with approximately 30% basalt stones (some of which are broken groundstones). Begins to thin out from half of square running east. Represents either leveling or building up of ground level.',NULL,NULL,'?'),(81,10,77,'S9','2013-06-13 00:00:00','2013-06-13 00:00:00','11.36','11.36','13/S/14, 13/S/31, 13/S/33, 13/S/42',NULL,NULL,'Cleaning/closing locus left a spread of small fieldstones across most of square and a small area of probable surface comprised of a mid brown silty clay beaten earth surface. Pottery collection from within surface includes high proportion of KKW ware.',NULL,NULL,'?'),(82,10,78,'T8','2013-06-13 00:00:00','2013-06-13 00:00:00','12.99','12.99',NULL,NULL,NULL,'Final clean/closing locus of square. No pottery collected.',NULL,NULL,'?'),(83,14,1,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'?'),(84,14,2,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'?'),(85,15,101,'Trench Sa 1','2015-05-26 00:00:00','2015-06-08 00:00:00',NULL,NULL,'-','15/S/102, 15/S/103, 15/S/109',NULL,'Topsoil 1x8 m running north south. Loose, grainy soil, light brown with field stone inclusions. Nails and metal run the surface.',NULL,NULL,'?'),(86,15,102,'Trench Sa 1','2015-05-27 00:00:00','2015-05-28 00:00:00',NULL,NULL,'15/S/101','15/S/108',NULL,'This is the articulation of the stones on the path that runs nearly 3 meters NS. The stones are medium to small field stones close together and nearly level at the surface. The pottery is late and very few diagnostics.',NULL,NULL,'?'),(87,15,103,'Trench Sa 1','2015-05-28 00:00:00','2015-06-03 00:00:00',NULL,NULL,'15/S/101','-',NULL,'Southern most meter and a half of the trench next to the stone path. Absence of path and smaller pebbles, rocks to cobble field stones. A soil matrix with more pottery that leads down to a hard surface with a mixture of pottery, bone and flint.',NULL,NULL,'?'),(88,15,108,'Trench Sa 1','2015-06-04 00:00:00','2015-06-08 00:00:00',NULL,NULL,'15/S/102','15/S/103 ?',NULL,'Taking down of a section of the path on the south part of the trench in a 2x1 m probe to find the hard surface that the path might sit on and also to see how deep the stones are in the path. We did not dig below Locus 15/Sa/103 but the stones seem to rest on the surface. This locus is a mixture of field stones as well as the dirt underneath- loose and brown with pebble and fieldstone inclusions.',NULL,'The pottery was mixed with mostly wadi rabah, EB and one Roman/Byzantine. We also found flint blades and a piece of worked pottery.','?'),(89,15,109,'Trench Sa 1','2015-06-08 00:00:00','2015-06-09 00:00:00',NULL,NULL,'15/S/101','15/S/110',NULL,'A small section in the northwest corner of the 8x1 m trench next to the path but lower. This section had no rocks in it but was brown loose dirt with small pebble inclusions. We dug down to the rocks. Along with late material we had Wadi Rabah and some flint.',NULL,NULL,'?'),(90,15,110,'Trench Sa 1','2015-06-09 00:00:00','2015-06-10 00:00:00',NULL,NULL,'15/S/109','15/S/112',NULL,'In the NE corner of the 1x8 trench Sa we moved from dirt to a level of highly compacted rocks that look as if they could be part of an earlier version of the path and that sits next to or continues through Locus 15/S/102 (the path). The pottery (not much) was Wadi Rabah with a few later pieces along with bones and flint.',NULL,NULL,'?'),(91,15,111,'Trench Sa 3','2015-06-10 00:00:00','2015-06-12 00:00:00',NULL,NULL,'-','-',NULL,'Topsoil loose, gray/brown, pebble field stone inclusions over top a tuff path similar to the path excavated in 2014.',NULL,NULL,'?'),(92,15,112,'Trench Sa 1','2015-06-14 00:00:00',NULL,NULL,NULL,'15/S/110','-',NULL,'Stone installation with larger body shard vertical in stone installation located in the NE corner of the 1x8 m trench next to but lower than the road. The stones next to the installation are tightly interwoven. The installation is roughly 13 cm deep. In this tiny area we found  (not read yet) pottery and flint and also a worked sherd.',NULL,NULL,'?'),(93,15,201,'Trench 2','2015-05-26 00:00:00','2015-05-27 00:00:00','16.26/16.16','16.03/15.83','None','15/S/202',NULL,'Trench 4x1 m oriented NW-SE encroaching on first line of chickpeas at the westernmost side of the \"Masha\" halfway between \'Ein Jezreel and the winery. Locus closed upon reaching slightly more yellowish soil at about 40 cm deep from soil level.','Topsoil. Compact despite ploughing. Dark brown with small to medium stones. Metal detector on surface found 3 large modern nails. A few shards of modern glass (window panes), bolt, tesserae, coin, ceramic token, very few pottery, flint, broken grindin',NULL,'?'),(94,15,202,'Trench 2','2015-05-27 00:00:00','2015-05-28 00:00:00','16.03/15.83','15.81/15.8','15/S/201','15/S/203',NULL,'Subsoil. First locus beneath topsoil. Mud bricks and one slanted stone with plaster on top.','Below 15/S/201. Slight change in soil color. No modern coins, glass, etc. Upon reaching the field of medium stones with pottery shards stuck in bewtte',NULL,'?'),(95,15,203,'Trench 2','2015-05-28 00:00:00','2015-05-29 00:00:00','15.81/15.8','15.78/15.53','15/S/202','15/S/204',NULL,'Fill of medium stones with pottery shards between stones. Locus closed upon reaching gray, slightly ashy material in southeastern corner. Composition remains the same.','Color similar to 15/S/201 but slightly lighter. Sporadic chalk deposits. Fill of medium field stones embedded with pottery shards, mostly of large storage jars, very compact. Had to excavate using crowbar. Very few flints, few bones, one mortar stone.',NULL,'?'),(96,15,204,'Trench 2','2015-05-31 00:00:00','2015-05-31 00:00:00','15.78/15.53','15.26/15.18','15/S/203','15/S/205',NULL,'Fill of stones and sporadic pottery. Closed locus due to decrease in stone size and decrease in presence of pottery.','Fill of stones (slightly smaller than stones in 15/S/203). Less pottery than in 15/S/203. Grey, light grey color soil. Very few flints and bones.',NULL,'?'),(97,15,205,'Trench 2','2015-05-31 00:00:00','2015-05-31 00:00:00','15.26/15.18','15.1/14.77','15/S/204','15/S/206',NULL,'See 15/S/204.','Similar to 15/S/204. Medium field stones and less pottery',NULL,'?'),(98,15,206,'Trench 2','2015-06-01 00:00:00','2015-06-01 00:00:00','15.1/14.77','14.39/14.39','15/S/205','None',NULL,'Next to (west of) 15/S/205 (eastern end of trench). Clay and organic material. Only half of trench excavated.','Layer of fine uncompacted soil, light color, with very few stones',NULL,'?'),(99,15,301,'H6','2015-05-27 00:00:00','2015-05-29 00:00:00','13.79/13.63','13.50/13.28','None','15/S/306',NULL,'Opening locus of square. Clear topsoil & clean square.','1. Topsoil.  2. Loose.   3. Greyish brown.  4. Silt.  5. Frequent small to medium sized rocks.  6. 4 x 4 m. N-S, 4 x 4 m. E-W.  7. Large ant hill in NE sector, high number of pottery and flint pieces; a few animal burrows in southern third of square. Seven metal artifacts.',NULL,'?'),(100,15,302,'H7','2015-05-27 00:00:00','2015-05-28 00:00:00','13.71/13.31','13.5/13.24','None','15/S/305',NULL,'Opening locus of square. Clear topsoil & clean square. Pottery mixed.','1. Topsoil. 2. Loose. 3. Greyish brown. 4. Slightly sandy silt. 5. Frequent small - med. rocks, pottery, flint, occ. bone. 6. 4 x 4 m. N-S, 4 x 4 m. E-W.  7. Occ. basalt, freq. rooting action.',NULL,'?'),(101,15,303,'J6','2015-05-27 00:00:00','2015-05-29 00:00:00','14.48/14.47','14.261/13.964','None','15/S/304',NULL,'Opening locus of square. Clear topsoil & clean square. Pottery mixed from Chalcolithic to modern.','1. Topsoil.  2. Loose.  3. Greyish brown.  4. Silt.  5. Frequent small to medium sized rocks.  6. 4 x 4 m. N-S, 4 x 4 m. E-W.  7. Large ant hill in NE sector, high number of pottery and flint pieces; a few animal burrows in southern third of square. Seven metal artifacts.',NULL,'?'),(102,15,304,'J6','2015-05-28 00:00:00','2015-06-01 00:00:00','14.261/13.964','14.15/13.68','15/S/303','15/S/309, 15/S/310',NULL,'Locus comprised of some type of stone layer. Potential wall extending from south baulk to central north baulk. Seperated pottery buckets PT3 to the west of potential wall and PT4 to the east. PT1 tag possibly switched and pottery may not belong to the locus. Removed \"potential wall\" which was only stone collapse. Pottery mixed from Wadi Raba to Roman/Byz.','1.  Layer.  2. Loose.  3. Greyish brown.  4. Silt.  5. Small-large stones, some mudbrick material, surface-like material in NE corner. 6. 4 x 4 m. N-S, 4 x 4 m. E-W.  7. Several worked stone artifacts, freq. rooting action.  Ants still in south.',NULL,'?'),(103,15,305,'H7','2015-05-28 00:00:00','2015-06-01 00:00:00','13.59/13.37','13.35/13.10','15/S/302','15/S/308',NULL,'In NE edge, encountered greyish surface material, appeared to cover majority of square. Encountered orangeish-brown soil that had frequent mudbrick chunks throughout square. Locus seems to be a stone cover. Pottery mostly EB, mixed with Byz & MB.','1. Layer. 2. Loose. 3. Greyish-brown to orangeish-brown. 4. Clay-like silt. 5. Frequent small-med. rocks, occ. med.-large rocks, few animal bone, frequent mud brick chunks, small concentration of surface-like material, frequent groundstone. 6. 4 m. N-S x 4 m. E-W. 7. Sixteen artifacts including basalt tools, flint blades, hammer stones, worked stone and an astragalus.',NULL,'?'),(104,15,306,'H6','2015-05-29 00:00:00','2015-06-01 00:00:00','13.50/13.28','13.28/13.13','15/S/301','15/S/307',NULL,'In SW corner of square, encountered greyish surface material which then appeared to cover the majority of the square, transitioned to reddish brown material. Locus seems to be some kind of stone cover. Pottery mixed with Wadi Raba to Arab.','1. Layer. 2. Moderately compacted, crumbled when excavated. 3. Reddish brown & greyish brown in patches. 4. Silt. 5. Medium to large rocks, some mudbrick material; surface-like material. 6. 4 x 4 m. N-S, 4 x 4 m. E-W.',NULL,'?'),(105,15,307,'H6','2015-06-01 00:00:00','2015-06-05 00:00:00','13.28/13.13','13.14/12.96','15/S/306','15/S/315, 15/S/311',NULL,'Stone cover over entire square (similar to 15/S/306). On 2 June (PT2), opened a new locus to probe material beneath rock layer in NE corner (became locus 15/S/311 then 15/S/313). Pottery mixed from Wadi Raba to Roman-Byzantine.','1. Layer. 2. Tightly packed, med. to large field stones. 3. Reddish brown. 4. Silty. 5. Medium to large field stones, mudbrick, limestone. 6. Initially (PT1) 4 x 4 m. N-S, 4 x 4 m. E-W.  PT2 - PT4 entire square except NE corner (15/S/311 and 15/S/313).',NULL,'?'),(106,15,309,'J6','2015-06-01 00:00:00','2015-06-11 00:00:00','14.26/13.96','13.41/13.11','15/S/303, 15/S/304','15/S/312, 15/S/318','15/S/310','Locus started as stone layer similar to 15/S/304. Cleared stone layer of varying sizes throughout the square approx. 1.1m in depth. Encountered bits of mudbrick throughout the square and reached surface-like material. Locus contained 23 artifacts that were mostly worked basalt. Pottery mixed.','1. Layer (stone). 2. Loose. 3. Greyish-brown. 4. Silt. 5. Small-large field stones, mudbrick, limestone, \"surface-like\" material. 6. 4 x 4 m. N-S,  4 X 4 m. E-W. 7. Lots of stone artifacts (worked stone), roots, bioturbation.',NULL,'?'),(107,15,310,'J6','2015-06-01 00:00:00','2015-06-11 00:00:00','14.15/13.68','13.75/13.65','15/S/303, 15/S/304',NULL,'15/S/309','Locus opened because of potential wall but now combined with 15/S/309. See 15/S/309.','See 15/S/309.',NULL,'?'),(108,15,312,'J6','2015-06-03 00:00:00','2015-06-08 00:00:00','13.71/13.65','13.33/13.23','15/S/309','15/S/316',NULL,'2 x 2 m. in NW corner. Approximately 46 cm. deep of compacted surface-like material.','1.  Layer. 2. Compact. 3. Darker brown. 4. Slightly clay-like. 5. Mudbrick, small stones, several pieces of large bone, numerous pottery, some flint, ground stone, roots. 6. 2 x 2 m. N-S, 2 x 2 m. E-W:  NW corner. 7. Animal burrows in baulk.',NULL,'?'),(109,15,401,'C11','2015-05-26 00:00:00','2015-05-29 00:00:00','11.24/10.84','10.52/10.06','None','15/S/410, 15/S/412',NULL,'Topsoil','1. Topsoil  2. Loose  3. Greyish brown  4. Sandy silt  5. Freq. small fieldstones  6. 4 m. N-S x 4 m. E-W  7. Freq. root action',NULL,'?'),(110,15,402,'D11','2015-05-26 00:00:00','2015-05-28 00:00:00','11.78/11.16','11.69/11.13','None','15/S/409',NULL,'Topsoil','1. Topsoil  2. Loose, friable  3. Gray/brown  4. Sandy, silt  5. Frequent small & medium field stones, occasional fragments, burned mudbrick  6. 4 x 4 x 0.17 m.',NULL,'?'),(111,15,403,'C12','2015-05-26 00:00:00','2015-05-29 00:00:00','11.1/10.7','10.87/10.7','None','15/S/411',NULL,'Surface clearing and reduction in topsoil. Moderate amounts of tumble pottery and flint. Few animal bones.','1. Topsoil  2. Crumbly with no compaction  3. Light gray  4. Clayish topsoil  5. Small pebbles and medium size rocks  6. 4 x 4 x 0.5 m.',NULL,'?'),(112,15,404,'C13','2015-05-26 00:00:00','2015-05-27 00:00:00','10.92/10.6','10.87/10.8','None','15/S/406',NULL,'Topsoil','1. Topsoil  2. Loose  3. Greyish brown  4. Sandy silt  5. Freq. small to medium stones  6. 4 m. N-S x 4 m. E-W x 0.30 m. D.',NULL,'?'),(113,15,405,'D13','2015-05-26 00:00:00','2015-05-28 00:00:00','11.25/10.86','11.02/10.89','None',NULL,NULL,'Surface clearing, topsoil.','1. Topsoil  2. Loose soil  3. Light greyish brown  4. Loose topsoil  5. Field stones, pebbles',NULL,'?'),(114,15,406,'C13','2015-05-27 00:00:00','2015-05-28 00:00:00','10.87/10.8','10.66/10.59','15/S/404','15/S/407',NULL,'We closed the locus after exposing the stone inclusion layer across the entire square.','1. Layer  2. Loose soil, more compact than topsoil  3. Brown  4. Slightly sandy clay  5. Inclusions: a few cm. down approached a level w/ many small to medium stones -- field stones  6. 4 m. N-S x 4 m. E-W, D 28 cm.',NULL,'?'),(115,15,407,'C13','2015-05-28 00:00:00','2015-06-01 00:00:00','10.66/10.059','10.62/10.27','15/S/406','15/S/420',NULL,'The layer was the same as the above, 15/S/406, with a separation of a flat, possible beaten earth surface between the above 15/S/406 and 15/S/407. This locus sat on the basalt bedrock.  The possible surface was noted in the NW and in the SE. The basalt had an outer crumbly layer (tuff). Pottery suggests Roman/Byz deposit.','1. Layer  2. Loose soil  3. Brown  4.  Slightly sandy clay  5.  Frequent small to medium size field stones  6. 4 m. N-S x 4 m. E-W',NULL,'?'),(116,15,408,'D13','2016-05-28 00:00:00','2015-05-31 00:00:00','11.07/10.78','10.8/10.76','15/S/405','15/S/417',NULL,'Subsoil','1. Layer  2. Loose  3. Dark/rich brown  4. Silty clay  5. Basalt, worked basalt  6. 4 m. N-S x 4 m. x  0.13 m. D.',NULL,'?'),(117,15,411,'C12','2015-05-29 00:00:00','2015-05-29 00:00:00','10.87/10.80','10.77/10.57','15/S/403','15/S/414',NULL,'Dark subsoil right beneath a crumbly topsoil. Contained few rocks and moderate amount of pottery and flint.','1.  Subsoil  2. Moderately compact  3.  Dark greyish-brown  4.  Clay subsoil  5.  Small pebbles and a few medium size rocks         6. 4 x 4 m.',NULL,'?'),(118,15,414,'C12','2015-05-29 00:00:00','2015-05-31 00:00:00','10.78/10.57','10.63/10.54','15/S/411','15/S/415',NULL,'Below topsoil layer of fine dirt which when compacted was a hard layer. Contained small amounts of pottery, which looked mainly Roman and Arab, and small amounts of flint. The lower end of the locus contained many more rocks, possibly suggesting a wall.','1. Below topsoil.  Mudbrick collapse? Sandy?  2. Heavily compacted, very fine when broken apart  3. Dark brown color  4.  Heavily compacted dirt with small amounts of clay-like material  5.  Small amounts of medium sized stones  6.  4 x 4 m.',NULL,'?'),(119,15,415,'C12','2015-05-31 00:00:00','2015-06-02 00:00:00','10.63/10.54','10.45/10.21','15/S/414','15/S/420',NULL,'Suspected terrace fill from the Roman period of occupation based on the majority of pottery found. Area of digging was reduced to a 2 x 2 x 0.8 m. square to quickly probe the area to bedrock.  Pottery was quite plentiful towards the opening of the square but began to slow down towards bedrock.','1. Sandy silt  2. Compacts firmly but fine when loose  3. Dark brown  4. Very fine subsoil   5. Small amounts of pibbles and a few larger stones  6. Started as 4 x 4 x 0.4 m., finished as 2 x 2 x 0.8 m.',NULL,'?'),(120,15,421,'F13','2015-06-02 00:00:00','2015-06-03 00:00:00','12.34/11.63','12.16/11.7','15/S/419','15/S/425',NULL,'Topsoil. Found a turkish/ottoman pipe in this layer. Found sherds of a thin metal object sticking into this locus but clearly standing in the locus below. Closed locus when arrived to a new brownish soil below. On the north half of the square, we left many of the small to medium sized fieldstones to further explore what they are doing there.','1. Topsoil  2. Loose  3. Grey  4. Gritty silt  5. Many small to middle-sized stones  6. 4 m. N-S x 4 m. E-W x 0.09 m. D',NULL,'?'),(121,15,422,'G13','2015-06-02 00:00:00','2015-06-03 00:00:00','12.78/12.28','12.64/12.25','None','15/S/423',NULL,'Surface cleaning','1. Topsoil  2. Crumbly topsoil  3. Light grey 4. Sandy-silt  5. Small pebbles and medium size stones  6. 4 x 4 x 0.2 m.',NULL,'?'),(122,15,423,'G13','2015-06-03 00:00:00','2015-06-03 00:00:00','12.64/12.25','12.23/12.12','15/S/422','15/S/429',NULL,'Subsoil reduction with rock articulation. Moderate amounts of pottery found that looks to belong to Roman/Byzantine and earlier. Some flint found and very few bones. Basalt artifacts found as well.','1. Subsoil  2. Crumbled soil  3. Light grey  4. Top soil and sandy silt  5. Small pebbles and medium size field stones  6. 4 x 4 x 0.3 m.',NULL,'?'),(123,15,426,'D11','2015-06-03 00:00:00','2013-06-08 00:00:00','11.66/11.37','11.57/11.27','None',NULL,NULL,'Expansion of the square westward because of 15/S/W3 in the baulk. High concentration of flint cores. Believed rock tumble from 15/S/W3 throughout locus.','1. Topsoil  2. Loose  3. Black/brown  4. Silty  5. Small/medium field stones  6. 4m. N-S x 0.91 m. E-W (north side), 1.08 m. (south side)',NULL,'?'),(124,15,429,'G13','2015-06-03 00:00:00','2015-06-05 00:00:00','12.23/12.12','12.54/12.07','15/S/423','15/S/431',NULL,'Leveling and reduction of the square north of the basalt socket. Moderate amounts of pottery with moderate flint nodes that included several large nodes. Small pebbles and field stones began to appear as the level was reduced in the northern corner.','1. Subsoil  2. Lightly to moderately compacted  3. Brownish grey  4. Sandy silt  5. Small pebbles and small field stones  6. 4 x 4 x 0.4 m.',NULL,'?'),(125,15,104,'Trench Sa 2','2015-05-29 00:00:00','2015-05-31 00:00:00',NULL,NULL,'-','15/S/105',NULL,'1x4 m trench. Topsoil, loose, gray/brown. Field stone inclusions, modern and ancient metal (nails, shrapnel and other metals) and flint.',NULL,NULL,'?'),(126,15,105,'Trench Sa 2','2015-05-31 00:00:00','2015-06-01 00:00:00',NULL,NULL,'15/S/104','15/S/106',NULL,'The level layer of small to medium field stones that cover the entire 4x1 m trench and their removal in the northernmost 1x2 m probe. In this locus we found flint blades, a pounding stone and a tesserae along with a possible Iron I piece of pottery and EBI and EBII, burnished ware, Khirbet Kerak and later material.',NULL,NULL,'?'),(127,15,106,'Trench Sa 2','2015-06-01 00:00:00','2015-06-01 00:00:00',NULL,NULL,'15/S/105','15/S/107',NULL,'The removal of soil  in a 1x2 m north probe under stones (15/S/105)- loose, darker brown, small field stone inclusions, more rocks noticeable on eastern side of the probe. The pottery was indistinguishable and we found a few shells and flint mixed within the soil.',NULL,NULL,'?'),(128,15,107,'Trench Sa 2','2015-05-31 00:00:00','2015-06-01 00:00:00',NULL,NULL,'15/S/106','-',NULL,'Compacted dark, clay-like, charcoal flecks as well as white chalk inclusions. What little pottery we had was unidentifiable. We dug to a depth of 1.288 m of this locus.',NULL,NULL,'?'),(129,15,308,'H7','2015-06-01 00:00:00','2015-06-10 00:00:00','13.35/13.05','12.73/12.62','15/S/305','15/S/314',NULL,'This locus is comprised of small-large fieldstones and freq. mudbrick debris. The locus was divided into quadrants (see PT description in notes). Over 42 artifacts (including freq. flint blades and worked stone) and three full buckets of basalt. Pottery was mainly EB but mixed with everything from Wadi Raba to Roman/Byz.','1. Layer. 2. Loose dirt then tightly compacted rocks then loose sand. 3. Greyish-brown to orangeish-brown. 4. Clay-like sandy silt. 5. Frequent small to large rocks, occ. mudbrick, occ. bone, occ. roots, freq. basalt. 6. 4 m. N-S x 4 m. E-W. 7. Found a lot of pottery and basalt in this locus.','*PT1-2: Entire square. \n PT3 & 5-7: West half of square.\n PT4 & 11: NE corner of square.\n PT8: East half of square.\n PT9-10: SE corner of square.','?'),(130,15,311,'H6','2015-06-02 00:00:00','2015-06-03 00:00:00','13.31/13.10','13.00/12.89','15/S/307','15/S/113',NULL,'Similar to locus 15/S/307. Just focused in NE corner. Pottery mixed from KKW to Roman/Byzantine.','1. Layer. 2. Tightly packed medium to large fieldstones. 3. Reddish brown. 4. Silty. 5. Medium to large fieldstones. 6. Roughly 2 x 2 m. N-S, 2 x 2 m. E-W, NE corner.',NULL,'?'),(131,15,313,'H6','2015-06-03 00:00:00','2015-06-10 00:00:00','13.00/12.89','12.83/12.66','15/S/311',NULL,NULL,'Continuation of probe (locus 15/S/311). Locus changed because thought excavated stone cover, however, encountered more stones which decreased in number as work progressed. Continued locus until encountered, \"surface.\"','1. Surface-layer. 2. More compact. 3. Grey-brown to darker brown to grey. 4. Silt. 5. Transitioned from large rocks to fewer and smaller rocks. 6. 2 m. N-S x  2 m. E-W ( NE corner).',NULL,'?'),(132,15,314,'H7','2015-06-05 00:00:00','2015-06-10 00:00:00','12.90/12.65','12.87/12.69','15/S/308','15/S/323, 15/S/324, 15/S/329',NULL,'Locus contained a layer of rocks and mudbrick chunks, followed by a layer of packed earth, followed by more packed earth with frequent pebbles and pottery sherds. Flat-lying pottery noticed in PT3 may be part of the pit (locus 329). Pottery should be read with pit (15/S/329). Possible restoration.','1. Layer. 2. Compact at the top with mudbrick chunks & packed earth, transitioned to looser material near end of locus. 3. Orangey-brown to light brown. 4. Clay-like silt to sand. 5. Frequent mudbrick chunks, including giant intact mudbrick, occ. ash, frequent, \"surface-material\" and pebbles. 7. PT1&2: 4 m. N-S x 2 m. E-W; PT3: 4 m. N-S x 4 m. E-W.','All PTs to Noga for restoration.','?'),(133,15,315,'H6','2015-06-05 00:00:00',NULL,'13.14/12.96','12.74/12.63','15/S/307',NULL,NULL,'Locus 15/S/ 315 opened to reach level of possible surface noticed in NE corner (15/S/313). Contained a large number of pottery sherds, a mixed assemblage with pieces from Wadi Raba to Roman/Byzantine.','1. Layer. 2. Loose soil. 3. Reddish brown. 4. Silt. 5. Varying sizes of fieldstones, from large to small; numbers decreased according to depth. 6. Entire square except for NE corner (2 m. N-S x 2 m. E-W).',NULL,'?'),(134,15,316,'J6','2015-06-05 00:00:00','2015-06-17 00:00:00','13.33/13.23','13.18/13.14','15/S/312','15/S/332',NULL,'Surface - maybe in association with 15/S/312.\nThis locus is the surface and the removal of it. The surface is approximately 25 cm. deep and may be in association with W006. The surface contained flat-lying pottery, worked sherds, and a stone vessel piece (of a bowl). PT1 contained all early material.','1. Layer, surface. 2. Compacted and mudbrick/surface-like. 3. Brownish. 4. Silt. 5. Mudbrick, pottery had lime deposit due to sealing under stone cover. 6. 2 x 2 m. N-S, 2 x 2 m. E-W. 7. Animal burrows, roots.',NULL,'?'),(135,15,317,'F6','2015-06-10 00:00:00','2015-06-12 00:00:00','12.61/12.49','12.33/12.27','None','15/S/321, 15/S/323',NULL,'Opening locus. Cleared topsoil to expose architecture (wall 15/S/007 = 14/S/W002). Pottery contained no Roman or Byz. sherds, but Wadi Raba and possible MB/LB.','1. Topsoil. 2. Loose. 3. Greyish-brown. 4. Silt. 5. Frequent small to medium fieldstones. 6. Approx. 2 x 2 m. N-S & 2 x 2 m. E-W. in southern part of the square.',NULL,'?'),(136,15,318,'J6','2015-06-10 00:00:00','2015-06-17 00:00:00','13.32/13.28','13.30/13.04','15/S/309',NULL,NULL,'This locus is composed of a layer of mudbricks. The mudbricks seem to be running parallel in line with mudbrick running N-S in the center of the square that may be in situ. This mudbrick may be a possible wall collapse or have collapsed from W006. Mudbrick extends to W006 but with no real defined mudbricks near the wall. This locus contained eleven artifacts, mostly of worked stone but also worked sherds and flint.','1. Layer of mudbrick. 2. Compact. 3. Greyish-brown with patches of red on W side of the square. 4. Bricky/silty with small frag. of pottery, flint & pebbles. 5. Small frag. of pottery, flint & pebbles, smaller to medium stones. 6. Entire 4 x 4 m. square minus 2 x 2 m. in NW corner (locus 15/S/312 & 15/S/316). 7. Animal burrows just above mudbrick in baulk.','*Pottery from S. baulk from mouse hole. - 18/6','?'),(137,15,319,'H6','2015-06-10 00:00:00','2015-06-12 00:00:00','12.96/12.82','12.78/12.71','15/S/315',NULL,NULL,'Excavated as a pit due to lack of stones noticed in baulk (SW corner), including sifting a few buckets of soil. Determined not to be a pit. This locus should be combined with 15/S/320. Pottery mixed from EB to possible Hellenistic.','1. Layer. 2. Compact and loose patches of soil throughout. 3. Light brown. 4. Silt. 5. Varying sizes - from small to large - fieldstones; mudbrick material. 6. 2 m. N-S x 2 m. E-W.',NULL,'?'),(138,15,320,'H6','2015-06-10 00:00:00','2015-06-12 00:00:00','12.92/12.79','12.72/12.58','15/S/315',NULL,NULL,'Opened locus adjacent to possible pit (15/S/319) to move through \"surface\" first exposed in locus 15/S/313. Encountered medium sized rocks on third and final day of excavating this locus.','1. Layer. 2. More compact soil. 3. Greyish-beige color. 4. Silt. 5. Surface like material, medium sized rocks at PT3. 6. 2 m. N-S x 2 m. E-W, SE corner.',NULL,'?'),(139,15,321,'F6','2015-06-10 00:00:00','2015-06-12 00:00:00','12.50/12.38','12.18/12.05','15/S/317',NULL,NULL,'This locus was below the topsoil and subsoil of square F6. This locus was located in the soutwest corner of the square and west of wall W007.','1. Layer. 2. Compact. 3. Brownish-grey color. 4. Clay-like with some silt. 5. Mostly medium sized fieldstones with some small ones. 6. 135 cm. N-S x 100 cm. E-W/35 cm. E-W.',NULL,'?'),(140,15,322,'F6','2015-06-10 00:00:00','2015-06-11 00:00:00','12.33/12.27','12.01/11.91','15/S/317',NULL,NULL,'This locus is below the topsoil and subsoil. It is located in the southeast corner of square F6, east of wall W007. Uncovered top of wall W009, which may form right angle with W007. The pottery consisted of mainly EB sherds.','1. Layer. 2. Compact. 3. Brownish-grey color. 4. Clay-like with some silt. 5. Large fieldstones and possible tumble from W007. Also a few medium and small stones. 6. Length: 280 cm. Width: 120 cm. 7. Larger pottery sherds recovered in this locus.',NULL,'?'),(141,15,323,'H7','2015-06-10 00:00:00',NULL,'12.87/12.69','12.59/12.23','15/S/308, 15/S/314','15/S/324, 15/S/329',NULL,'Locus was excavated as a possible surface, including sifting every bucket of dirt. Locus was inundated with small pottery sherds and has many potential restoration vessels that go with loci 15/S/314 & 15/S/329 (PT1, 3, 4 & 7 from this locus to be read with loci 314 & 329). Encountered flat-lying pottery at end of locus.','1. Layer. 2. Packed earth followed by loose sand containing freq. pottery sherds and pebbles-small fieldstones. 3. Light brown to orange-ish brown. 4. Very compact clay-like earth then loose sand. 5. Freq. small fieldstones & pebbles, freq. small pottery sherds. 6. 2 m. N-S x 4 m. E-W. 7. Removed pivot in SE quadrent of locus, removed base for residue analysis. Locus was inundated with pottery.',NULL,'?'),(142,15,324,'H7','2015-06-11 00:00:00',NULL,'12.95/12.83','12.66/12.61','15/S/323',NULL,NULL,'Locus was a layer including freq. mudbrick & fieldstones in the SW quadrant of the square.','1. Layer. 2. Clay-like silt. 3. Light brown to orangey-brown to dark brown. 4. Packed earth to loose dirt to packed earth again. 5. Frequent small to medium fieldstones, freq. mudbrick. 6. Approx. 1 m. N-S x 2 m. E-W.',NULL,'?'),(143,15,325,'H6','2015-06-12 00:00:00','2015-06-15 00:00:00','12.74/12.63','12.05/11.94','15/S/313, 15/S/315','15/S/330',NULL,'Locus opened to probe the area running 1 m. N-S and 4 m. E-W in the northern part of the square.','1. Layer. 2. PT1-3: More compact soil, especially in NW corner; PT4 (NE corner): more loose soil. 3. PT1-3: beige soil, PT4 dark brown soil. 4. PT1-3: possible mudbrick material, PT4: silty. 5. NW corner included many small fieldstones. 6. 1 m. N-S x 4m. E-W in north of square.',NULL,'?'),(144,15,326,'E5/E6','2015-06-14 00:00:00','2015-06-14 00:00:00','12.40/12.10','12.09/11.92',NULL,NULL,NULL,'Topsoil and subsoil from removal of E5/E6 baulk.','1. Layer - topsoil/subsoil. 2. Relatively loose soil. 3. Light brown. 4. Silty soil. 5. Medium to small sized inclusions/stones; some possible tumble from curvilinear wall W008. 6. 400 cm. x 160 cm. x 6 cm.',NULL,'?'),(145,15,327,'E5/E7','2015-06-14 00:00:00','2015-06-15 00:00:00','12.09/12.01','12.01/11.99','15/S/326','NFE',NULL,'North of wall. Area inside of wall W008. Stopped excavating at NE corner of square E5.','1. Layer. 2. Loose. 3. Greyish-brown. 4. Silty. 5. Small fieldstones. 6. 140 cm. N-S x 115 cm. E-W, north of W008. 7. Greater concentration of pottery on inside of wall 008.',NULL,'?'),(146,15,328,'E6','2015-06-14 00:00:00','2015-06-15 00:00:00','12.19/12.09','11.83/11.72','15/S/326','15/S/335',NULL,'South of wall. Between locus 15/S/326 and 15/S/335 (stratagraphically). It is positioned south of wall 008. Eventually we came down on a hard white surface material, locus 15/S/335.','1. Layer. 2. Loose. 3. Greyish-brown. 4. Silty. 5. Small fieldstones. 6. 190 cm. N-S x 100 cm. E-W. South of W008. 7. Fewer sherds compared to 15/S/327, north of W008.',NULL,'?'),(147,15,329,'H7','2015-06-15 00:00:00',NULL,'12.74/12.69',NULL,'15/S/314, 15/S/323',NULL,NULL,'Sami-circular pit surrounded by small-medium fieldstones. Pit contains mostly pottery sherds, including many large body sherds & many potential restorations. Pottery is to be read with loci 15/S/314 and 15/S/323.','1. Pit. 2. Very compact. 3. Light yellowish-brown to orangeish-brown to dark brown. 4. Clay. 5. Mudbrick (freq.), charcoal (occ.), ash (occ.), bones (few), small fieldstones (few). 6. Depth: 50 cm. Length (E-W): 116 cm. Width (N-S): 78 cm.  Extending into south baulk. Possibly surrounded by stones of approx. 19 x 12 cm. 7. Many potential restoration vessels, inundated with pottery (PTs 1&2).','All PT to Noga for restoration.','?'),(148,15,330,'H6','2015-06-15 00:00:00','2015-06-16 00:00:00','12.44/12.31','12.05/11.94','15/S/325',NULL,NULL,'Opened locus as a probe in NE corner. After approximately 12 cm. of soil, encountered bedrock among rusty-colored, clay-like soil.','1. Layer/bedrock  2. Loose soil until bedrock  3. Soil: dark brown; bedrock: reddish soil, bedrock corroded, chipped basalt  4. Fine, silty soil; bedrock-clay  5. Few limestone inclusions  6. 2 m. E-W x 1 m. N-S, in NE corner  7. Encountered bedrock at 12.26',NULL,'?'),(149,15,331,'E6','2015-06-16 00:00:00','2015-06-17 00:00:00','12.15/12.01','11.83/11.72',NULL,'NFE',NULL,'Locus opened to remove stone collapse that was erroneously considered 14/S/W7. Attempted to locate the possible path. Determined that the possible path did not extend beneath this erroneous wall (14/S/W7). *Encountered surface at 12.13. *Pottery EB.','1. Removal of wall 14/S/W7  2. Compact  3. Greyish-brown soil  4. ----   5. Large fieldstones  6. *Find dimensions of 14/S/W7.',NULL,'?'),(150,15,332,'J6','2015-06-16 00:00:00','2015-06-17 00:00:00','13.18/13.14','12.99/12.91','15/S/316',NULL,NULL,'This locus was opened to probe under suface in locus 15/S/316. Artifacts were minimal with a small piece of Roman glass and small bits of shell.','1. Layer  2. Compact  3. Dark brown/reddish  4. Silt/mudbrick  5. Chunks of deep red mudbrick rather than grey, small pebbles  6. 2 m. N-S x 2 m. E-W  7. Large cow bones (at least 4), animal burrows',NULL,'?'),(151,15,333,'F5','2015-06-16 00:00:00',NULL,'12.48/12.37',NULL,NULL,NULL,NULL,'Mudbrick debris, possibly from the erosion of wall 15/S/W011. Divided from rest of square by 15/S/W011 and pit (15/S/339). Possibly covering a surface.','1. Layer  2. Very compact  3. Grey  4. Mudbrick debris and fieldstones  5. Small to medium fieldstones  6. See locus sheet sketch for approximate dimensions.',NULL,'?'),(152,15,334,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'Triangular stone (?)\nTO CANCEL',NULL,'Assigned in error?','?'),(153,15,335,'E5/E6','2015-06-16 00:00:00','2015-06-18 00:00:00','12.09/11.95',NULL,'15/S/328','15/S/338',NULL,'Small surface @ 12.03 and its removal. As we removed surface we encountered patches of bedrock. The curvilinear wall is on top of bedrock. A few sherds of pottery were recovered, but a great concentration of flint.','1. Layer (surface)  2. Compact  3. Greyish  4. Silty  5. Medium to large fieldstones, also some small stones; great concentration of flint and blades  6. Approx. 190 cm. N-S x 100 cm. E-W, south of 15/S/W8  7. Encountered bedrock at the end of PT2. PT3 we scraped bedrock.',NULL,'?'),(154,15,336,'H6/J6','2015-06-17 00:00:00',NULL,NULL,NULL,NULL,NULL,NULL,'Basalt stone in baulk. Not excavated. Given locus number for plans.',NULL,NULL,'?'),(155,15,337,'F5','2015-06-17 00:00:00',NULL,'12.48/12.21',NULL,NULL,NULL,NULL,'Grey mudbrick debris/degraded mudbrick material containing frequent pottery, some flat-lying, and small to medium fieldstones.','1. Layer  2. Highly compact  3. Light gray  4. Mudbrick material/debris  5. Small to medium fieldstones  6. See locus sheet sketch for approx. dimensions.',NULL,'?'),(156,15,409,'D11','2015-05-28 00:00:00','2015-05-29 00:00:00','11.69/11.13',NULL,'15/S/402',NULL,'15/S/413','Subsoil','1. Below topsoil  2. Loose  3. Black/brown  4. Silty  5. Few small/medium fieldstones  6. 4 m. N-S x 1.94 m. E-W (south side) and 2.1 m. E-W (north side)',NULL,'?'),(157,15,410,'C11','2015-05-29 00:00:00',NULL,'11.58/11.24',NULL,'15/S/401',NULL,NULL,'Area between 15/S/W1 and 15/S/W5. Possible pit lines seen on 31 May (PT3). Pit found in section and numbered locus 15/S/442 in the baulk. Very dense semicircle of stones visible in 15/S/410 (this locus) prior to this.','1. Layer  2. Mixed loose and compact  3. Medium brown  4. Clay, silt  5. Mudbrick chunks, fired clay fragments, basalt flakes, small to medium fieldstones, bedrock, very little pottery or flint  6. 5 m. N-S x  2.67 m. E-W  7. More compact hard clay material running in 8 cm. wide strip along 15/S/W1, bedrock through most of N half.','PT10: Squarish area between 15/S/W1, bedrock to north and (removed) line of stones running south from bedrock\nPT11: Area north of PT10 between 15/S/W1, northern baulk and bedrock\n*See sketch','?'),(158,15,412,'C11','2015-05-29 00:00:00',NULL,'10.89/11.77',NULL,'15/S/401',NULL,NULL,'Area east of 15/S/W1. Originally all similar to 15/S/450 and C12, then single line of small fieldstones running from the wall to midsection in baulk. Soil south of stones is medium-dark brown soil seen in 15/S/450 and C12. North of line consistently saw several faint partial mudbrick lines. Soil is very mudbricky and compact, lighter brown, possible surface like that seen in 15/S/432 and 15/S/449. Bedrock uncovered in SW corner. NW corner running under wall and possibly extending into NE corner.','1. Layer(s)/surface (?) on north half  2. Midsection: compact, Corners (NE&SE): looser  3. Midsection: brown, Corners: darker brown  4. North of stones: dense clay, South of stones: sandy silt  5. Mudbrick fragments, basalt flakes, small fieldstones  6. 1.08 m. W 66 cm. W  3.75 m. L; 5 m.  7. 3 cm. strip of soil immediately next to wall is hard. Compact, claylike, midsection.','PT7 (16 June) - Mudbricky material north of line of stones\nPT8 (17 June) - \"vegetable garden\" material south of line of stones','?'),(159,15,413,'D11','2015-05-29 00:00:00','2015-05-31 00:00:00','11.58/11.24','11.21/11.01','15/S/402','15/S/418','15/S/409','Subsoil. West half of D11 below topsoil. Recognized possible collapsed wall. Cleared stones as they came loose, exposing a possible wall in the baulk.','1. Below topsoil  2. Loose, fine grain  3. Dark brown  4. Silty  5. Several medium to large fieldstones  6. 1.1 m. E-W x 4 m. N-S; 4 m. (in the baulk)',NULL,'?'),(160,15,416,'D11','2015-05-31 00:00:00','2015-06-03 00:00:00','11.21/11.01','11.20/10.89',NULL,NULL,NULL,'------ in wall. \n*Locus sheet unreadable',NULL,NULL,'?'),(161,15,417,'D13','2015-05-31 00:00:00','2015-06-09 00:00:00','10.85/10.72','10.53','15/S/408','15/S/424',NULL,'Possible sealing layer of fieldstones. Possible evidence of basalt workshop, inclusions of small chips of basalt.','1. Layer of dense rocks, subsoil (?)  2. Loose  3. Brown when moist, grey when dry  4. Silty clay  5. Frequent basalt, possible debitage, occasional burnt mudbrick  6. 4 m. N-S x 4 m. E-W x 0.25 m. D.',NULL,'?'),(162,15,418,'D11','2015-06-01 00:00:00',NULL,'11.19/11.02','11.16/10.88','15/S/413',NULL,NULL,'Divided the square in half due to difference in soil composition and stone density.','1. Thick layer  2. Mix of mudbrick and clay with some patches of loose soil  3. Brown  4. Clay  5. Some basalt chip inclusions, medium to large fieldstones  6. 2 m. N-S x 2 m. E-W','Locus closed because of the discovery of a wall.','?'),(163,15,419,'F13','2015-06-01 00:00:00','2015-06-02 00:00:00','12.38/11.68','12.34/11.63','None',NULL,NULL,'Cleaning, topsoil','Weeds above topsoil',NULL,'?'),(164,15,420,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'?'),(165,15,424,'D13','2015-06-03 00:00:00',NULL,'10.63/10.62','10.59/10.42','15/S/417',NULL,'15/S/448, 15/S/453?','Grey silt, few medium fieldstones, possible surface. Flatlying pot left in surface of east side of the locus.','1. Layer  2. Loose  3. Greyish brown  4. Silt  5. Fildstones, little to no basalt  6. 4 x 4 x 0.2 m.',NULL,'?'),(166,15,425,'F13','2015-06-03 00:00:00','2015-06-09 00:00:00','12.16/11.70','11.63/11.54','15/S/421','15/S/437',NULL,'Entire square of F13. Found metal sheet (part found 3/6/15, AR5 PT2)','1. Layer  2. Moderately compact (SW corner more compact)  3. Orange-brown  4. Clay  5. Frequent small to medium sized fieldstones  6. 4 m. N-S x 4 m. E-W  7. Subsoil',NULL,'?'),(167,15,427,'D11','2015-06-03 00:00:00','2015-06-17 00:00:00','11.20/10.89','10.89/10.69',NULL,'15/S/456',NULL,'-Between 15/S/W2 and 15/S/W3\n-Layer\n-Went through a layer of possible tumble\n-Found possible launch pad','1. Layer  2. Soft  3. Brown  4. Silty  5. Inclusions of mudbrick, tuff and ---- basalt. Came through some medium fieldstones','15/S/456 and 15/S/457 were part of 15/S/427 at some point. \nPossible launch pad floating (16 June)','?'),(168,15,428,'D11','2015-06-03 00:00:00',NULL,'11.09/10.91',NULL,NULL,'15/S/432, 15/S/433',NULL,'East of 15/S/W2. Reached a possible surface. Flat lying pottery. Still small fieldstones.','1. Layer  2. Soft/medium  3. Brown/black  4. Silty  5. Small fieldstones; high concentration of pottery sherds  6. 1.6 m. N-S x 0.60-0.66 m. E-W',NULL,'?'),(169,15,430,'G13','2015-06-04 00:00:00',NULL,'12.49/12.23',NULL,NULL,NULL,NULL,'Basalt socket',NULL,NULL,'?'),(170,15,431,'G13',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,'?'),(171,15,432,'D11','2015-06-08 00:00:00','2015-06-09 00:00:00','11.15/11.06','11.05/10.87','15/S/428','15/S/439',NULL,'South of wall (15/S/W2?). Near possible surface. Mudbrick inclusion.','1. Layer. 2. Sandy/clay/mudbrick. 3. Light brown. 4. Sandy. 5. Small field stones. 6. 1.1 m. N-S x 37 cm. E-W.',NULL,'?'),(172,15,433,'D11','2015-06-08 00:00:00',NULL,NULL,NULL,NULL,NULL,NULL,'North of 15/S/W2','Layer',NULL,'?'),(173,15,434,'D11','2015-06-08 00:00:00','2015-06-09 00:00:00','11.57/11.27','11.26/11.25','15/S/426',NULL,NULL,'Below topsoil in sandy red-brown soil with small to medium fildstones which may have been fill used as support for 15/S/W3 [intentional] because they were in close proximity to the west side of the wall but did not overlap like tumble. The rocks were close to the edge of the site where  it slopes down to the path.','1. Below topsoil [subsoil]  2. Medium  3. Brown-red  4. Sandy  5. Small to medium fieldstones [frequent]  6. 4 m. N-S x 0.92 m. E-W (north side) and 1.10 m. E-W (south side) Depth: 0.32 m.',NULL,'?'),(174,15,435,'C11','2015-06-08 00:00:00',NULL,'10.98/10.90',NULL,'15/S/401',NULL,NULL,'Area west of 15/S/W5. Came down on end of line of single line of stones extending from D11 and the C11/D11 baulk. End roughly corresponds with flat smooth large basalt stone next to 15/S/W5. Mainly bedrock to the north of this stone.','1. Layer  2. Loose  3. Medium brown  4. Silt, packed earth mainly to the north, sandy silt mainly to the south  5. Very rocky, lots of small to medium fieldstones as seen in D11\'s ------ , but less dense  6. 4-5 m. N-S x 0.89-0.92 m. E-W',NULL,'?'),(175,15,436,'C11/D11 baulk','2015-06-09 00:00:00','2015-06-14 00:00:00','11.34/11.14','11.27/11.07','None',NULL,NULL,'Topsoil - no flint, no bone','1. Topsoil  2.Loose  3. Dark brown  4. Sandy  5. Small fieldstones, minimal pottery  6. 1 m. N-S x 6 m. E-W, Depth: 0.12m',NULL,'?'),(176,15,437,'F13','2015-06-09 00:00:00','2015-06-17 00:00:00','11.99/11.82','11.22/11.14','15/S/425',NULL,NULL,'Opened this locus on S side of 15/S/W4. The SW corner acted slightly differently than the rest, with clean patches without stone inclusions at times, and at the bottom a possible mudbrick collapse or compacted soil, leading us to open a new locus on 16 June.','1. Layer  2. Moderately compact (SW corner more compact)  3. Orange-brown  4. Clay  5. Frequent small to medium sized stones  6. 1.20-1.40 m. N-S x 4 m. E-W, Depth: 0.80-1.00 m. 7. Below 15/S/425, south of 15/S/W4','Also to note, a line of three stones perpendicular to W4 and heading south toward G13 was noticed but removed. Could it possibly have been a wall connecting to a possible wall detected in G13? On June 16 we opened 15/S/462 on west end due to different soil.','?'),(177,15,438,'C11/D11 baulk','2015-06-09 00:00:00',NULL,'11.23/11.07',NULL,'15/S/436','15/S/441, 15/S/443, 15/S/444',NULL,'Subsoil',NULL,NULL,'?'),(178,15,439,'D11','2015-06-09 00:00:00',NULL,'11.05/10.87',NULL,'15/S/432',NULL,NULL,'Layer below 15/S/432 (possible surface) came down to bedrock.','1. Layer  2. Hard  3. Gray  4. Sandy  5. Basalt crumble, pottery inclusions',NULL,'?'),(179,15,440,'C11','2015-06-09 00:00:00',NULL,'10.97/10.83',NULL,NULL,NULL,NULL,'Strip between 15/S/W5 and bedrock on north baulk. (Below?) 15/S/435 and 15/S/410.','1. Layer  2. Mixed loose and compact, similar to 15/S/410  3. Medium brown  4. Clay, silt  5. Lots of small fieldstones  6. 1.80 m. N-S x 0.51 m. E-W','PT2 - Cleaning off top between 15/S/W5 and bedrock on N baulk, especially articulating N edge of W5 \nPT3 - Fill between bedrock on N baulk and midsection bedrock, bottom of fill seen in section by curved line of small rocks and pottery, large sherd forming edge, medium brown soil beneath','?'),(180,15,441,'C11/D11 baulk','2015-06-09 00:00:00',NULL,'11.22/11.12',NULL,'15/S/438?','15/S/451',NULL,'Area of baulk to west of (15/S/)W3/5(?) and on top of it, Exclusively to the west of W3/5 on PT1&2 (9&10 June). Includes top of wall on PT3 (11 June). Exclusively top of wall PT4 (14 June).  PT5 (16 June) was slump from SW corner between W5 and presumeed installiation in baulk. One EB holemouth rim found wedged under large stone from W5 and a piece of basalt bedrock.','1. Layer  2. Loose to W of W3/5, compact on top of wall  3. Dark brown  4. Silty  5. Lots of small fieldstones  6. 1.00 m. N-S x 1.65 m. E-W',NULL,'?'),(181,15,442,'C11/D11 baulk','2015-06-09 00:00:00','2015-06-09 00:00:00','11.07/10.98','10.98/10.94','15/S/443','15/S/455',NULL,'Half of bottom of pit extending north into 15/S/410, seen in baulk, other half of pit seen as semicircular group of stones in 15/S/410 but no pit lines were discerned.','1. Fill of pit seen in section; bottom of pit  2.Loose  3. Very dark brown  4. Silty  5. Med.-large stone on bottom next to NW stone edge  6. ----  7. Very little pottery','Andrea\'s pit','?'),(182,15,443,'C11/D11 baulk','2015-06-09 00:00:00','2015-06-12 00:00:00','11.09/11.05','11.07/10.84',NULL,'15/S/455',NULL,'Fill of pit 15/S/442','1. Fill of pit  2. Moderately compact  3. Midgreyish/orange brown  4.Slightly silty clay  5. ----  6. ----  7. Very little pottery',NULL,'?'),(183,15,444,'C11/D11 baulk','2015-06-09 00:00:00','2015-06-10 00:00:00','10.99/10.86','10.93/10.85',NULL,NULL,NULL,'Same soil continues in 15/S/450. \nSame as 450 - new locus changed too early.','Same as 15/S/450.\n1.0 m. N-S x 2.1 m. E-W',NULL,'?'),(184,15,445,'F13','2015-06-09 00:00:00','2015-06-11 00:00:00','11.71/11.66','11.68/11.58','15/S/425',NULL,NULL,'Opened this locus in NW of square. Working theory is a wall is running perpendicular and to the north from 15/S/W4.\n-It was determine dthat the abovementioned stones were not collapse or from another wall running N-S but were part of the fill in the 2.3-2.6 m. wide 15/S/W4.','1. Layer  2. A mixture of moderatly compact to still slightly loose topsoil  3. Brownish-orange  4. Clay  5. Many middle/small sized fieldstones throughout  6. 2.4 m. N-S x 4 m. E-W, Depth: 0.15 m.  7. Subsoil, north of 15/S/W4 (initially majority of square)',NULL,'?'),(185,15,446,'F13','2015-06-10 00:00:00','2015-06-11 00:00:00','11.63/11.54','11.36/11.24','15/S/445',NULL,NULL,'Installation?\nPossible restoration\n-PT1, vast majority of sherds were < 1-2 cm., mixed dates\nWe stopped digging the pit when we realized it cut into the inner fill between the two faces of 15/S/W4','1. Pit  2. Moderately compact  3. Orangish-brown  4. Clay  5. Cover or top with stones and beneath but middle was stone free  6. 0.90 m. N-W x 1.45 m. E-W, Depth: 0.40 m.',NULL,'?'),(186,15,447,'D11','2015-06-10 00:00:00',NULL,'11.26/11.25',NULL,NULL,NULL,NULL,'Blank locus sheet',NULL,NULL,'?'),(187,15,448,'D13','2015-06-10 00:00:00',NULL,'10.64/10.45','10.28/10.11','15/S/417, 15/S/424','15/S/453',NULL,'Orangish-red degraded bedrock material with inclusions of white plaster, chalk, or degraded limestone. Containing frequent smooth river pebbles (approx. 1-4 cm. dia.) and rare flint and potsherds.','1. Layer/possible surface?  2. Highly compact  3.Reddish and white  4. Plater debris?  5. Tuff, pebbles  6. 2 m. N-S x 4m. E-W x 0.35-0.40 m. deep',NULL,'?'),(188,15,449,'C11/D11 baulk','2015-06-10 00:00:00',NULL,'10.90/10.83','10.74/10.69',NULL,NULL,NULL,'\"L\" shaped area to the east of 15/S/450 (previously 15/S/444), south of 15/S/W1&15/S/412, and north of 15/S/433&15/S/433,15/S/428&15/S/W2. Several centimeters of mudbrick or packed earth material, not excavated out completely.','1. Layer/surface (?)  2. Dense, compact  3. Light brown  4. Mudbricky, packed earth  5. Sherds, very small stones  6. 1.56 m. N-S x 1.35 m. E-W',NULL,'?'),(189,15,450,'C11/D11 baulk','2015-06-10 00:00:00',NULL,'10.93/10.85','10.76/10.68',NULL,NULL,NULL,'Same soil as 15/S/444. Same \"vegetable garden\" material as seen in southern half of 15/S/412 and in square C12.','1. Layer  2. Loose  3. Medium brown  4. Sandy, silt  5. Bone, sherds, pebbles  6. 1.00 m. N-S x 0.69 m. E-W',NULL,'?'),(190,15,451,'D11','2015-06-10 00:00:00',NULL,'11.19/11.09',NULL,NULL,NULL,NULL,'Same as 15/S/441',NULL,NULL,'?'),(191,15,452,'G13','2015-06-10 00:00:00','2015-06-15 00:00:00','12.01/11.93','11.79/11.65','15/S/431','15/S/460',NULL,'Northwest corner of square after dividing square into two halves. Mudbrick material fount north of basalt socket. Suspected wall seperating mudbrick material from darker brown soil. Wall and soil reduced down to compact clay like soil.','1. Layer  2. ----  3. Light grey to brown  4. Sandy silt.  5. Small to medium fieldstones  6. 2 x 2 x 1 m.',NULL,'?'),(192,15,453,'D13','2015-06-11 00:00:00',NULL,'10.57/10.45','10.21/9.86','15/S/424','15/S/459',NULL,'Linear collection of rocks originally believed to be a foundation trench, led to notice of cut bedrock, lime/plaster of 15/S/448 on the south edge/side, soil of 15/S/448 on north side.','1. Possible foundation trench  2. Highly compact  3. Brownish grey  4. Silty clay  5. 0.50 m. N-S x 1.50 m. E-W x 0.30-0.40 m. deep',NULL,'?'),(193,15,454,'D11','2015-06-12 00:00:00',NULL,'11.50/11.15',NULL,NULL,NULL,NULL,'Locus sheet blank',NULL,NULL,'?'),(194,15,455,'C11/D11 baulk','2015-06-12 00:00:00','2015-06-14 00:00:00','11.07/10.84','10.88/10.74',NULL,NULL,NULL,'Rocky layer east of 15/S/442-3 and arch. materials from 15/S/442-3. Possible earlier installation in western part or true bottom of 15/S/443.','1. Rocky layer east of 15/S/442-3 and installation materials of 15/S/442-3  2. Loose  3. Light brown, dark brown  4. Silt, sand  5. Small and medium rocks  6. 1.00 m. N-S x 1.65 m. E-W','PT3 - Exclusively the area east of the stone circle \nPT4 - Same as above, series of very thin sherds, some glazed, found flat lying next to stone circle on SW side','?'),(195,15,456,'D11','2015-06-14 00:00:00','2015-06-19 00:00:00','11.06/10.94',NULL,NULL,NULL,NULL,'Layer of installation. \n-Found coin\n-Small amount of pottery \n-2 lines of small fieldstones 0.12 m. from bedrock surface of outer circle of installation\n-Located next to possible sewer drainage','1. Layer  2. Hard  3. Slity  4. Small to medium fieldstones  5. Burnt basalt  6. Inner: 0.34 m. Outer: 0.44 m.',NULL,'?'),(196,15,457,'D11',NULL,NULL,'11.09/10.96',NULL,NULL,NULL,NULL,'Section east of 15/S/W3 (southern corner)\n[to see if surface to match 15/S/432]',NULL,NULL,'?'),(197,15,458,'F13','2015-0